import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";

function Courses() {
  const user = useSelector((state) => state.auth.user);
  const [courses, setCourses] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [tests, setTests] = useState([]);

  useEffect(() => {
    if (user?.role === "student" && user.classId) {
      fetch(`http://localhost:3001/enrollments?userId=${user.id}`)
        .then((res) => res.json())
        .then((data) => {
          setEnrollments(Array.isArray(data) ? data : []);
          const courseIds = data.map((e) => e.courseId);
          if (courseIds.length > 0) {
            fetch(`http://localhost:3001/courses?id=${courseIds.join("&id=")}`)
              .then((res) => res.json())
              .then((courseData) => setCourses(Array.isArray(courseData) ? courseData : []))
              .catch((error) => toast.error("Ошибка загрузки курсов"));
            fetch(`http://localhost:3001/tests?courseId=${courseIds.join("&courseId=")}`)
              .then((res) => res.json())
              .then((testData) => setTests(Array.isArray(testData) ? testData : []))
              .catch((error) => toast.error("Ошибка загрузки тестов"));
          }
        })
        .catch((error) => toast.error("Ошибка загрузки записей"));
    } else if (user?.role === "teacher") {
      fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
        .then((res) => res.json())
        .then((data) => setCourses(Array.isArray(data) ? data : []))
        .catch((error) => toast.error("Ошибка загрузки курсов"));
    }
  }, [user]);

  if (!user) {
    return <div className="container mt-5"><h1>Пожалуйста, войдите в систему</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Курсы</h1>
      <div className="card shadow">
        <div className="card-body">
          <h2 className="card-title">
            {user.role === "student" ? "Ваши курсы" : "Ваши преподаваемые курсы"}
          </h2>
          {courses.length === 0 ? (
            <p>Нет курсов</p>
          ) : (
            <ul className="list-group">
              {courses.map((course) => (
                <li key={course.id} className="list-group-item">
                  <strong>{course.name}</strong>
                  {user.role === "student" && (
                    <div>
                      <h6>Тесты:</h6>
                      {tests.filter((t) => t.courseId === course.id).length === 0 ? (
                        <p>Тестов нет</p>
                      ) : (
                        <ul>
                          {tests
                            .filter((t) => t.courseId === course.id)
                            .map((test) => (
                              <li key={test.id}>
                                <Link to={`/take-test/${test.id}`}>{test.title}</Link>
                              </li>
                            ))}
                        </ul>
                      )}
                    </div>
                  )}
                  {user.role === "teacher" && (
                    <div>
                      <Link to={`/edit-course/${course.id}`} className="btn btn-secondary btn-sm me-2">
                        Редактировать
                      </Link>
                      <Link to="/add-test" className="btn btn-primary btn-sm">
                        Добавить тест
                      </Link>
                    </div>
                  )}
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

export default Courses;
